import json
with open('baseline-packages.json') as f: baseline = json.load(f)
with open('after-cpm-packages.json') as f: after = json.load(f)

# Build maps: {(project_basename, framework, package_id): resolved_version}
def build_map(data):
    m = {}
    for p in data['projects']:
        name = p['path'].split('/')[-1]
        for fw in p['frameworks']:
            for pkg in fw['topLevelPackages']:
                m[(name, fw['framework'], pkg['id'])] = pkg['resolvedVersion']
    return m

b = build_map(baseline)
a = build_map(after)

changes = []
unchanged = []
all_keys = sorted(set(list(b.keys()) + list(a.keys())))
for k in all_keys:
    bv = b.get(k)
    av = a.get(k)
    if bv and av and bv == av:
        unchanged.append(k + (bv,))
    elif bv and av and bv != av:
        changes.append(k + (bv, av, 'Aligned to highest version'))
    elif bv and not av:
        changes.append(k + (bv, 'REMOVED', 'Removed'))
    elif not bv and av:
        changes.append(k + ('N/A', av, 'Added'))

print('=== CHANGES ===')
for c in changes:
    print(f'{c[0]:15} {c[1]:8} {c[2]:45} {c[3]:10} -> {c[4]:10} | {c[5]}')

print()
print('=== UNCHANGED ===')
for u in unchanged:
    print(f'{u[0]:15} {u[1]:8} {u[2]:45} {u[3]}')
"

